// Lite Pack v1.2 · LLM helper（共用骨架，下面業務邏輯維持原樣）
// ⚠ 本 workflow 每筆 input 都打 1 次 LLM API。
// 若處理 > 10 筆 → 在 loop 內加 `if (i > 0) await lpThrottle();`
// 否則撞 Free tier 10 RPM 上限會 429。

// ════════════════════════════════════════════════════════════
// Lite Pack v1.2 · LLM Helper（共用骨架）
//
// 這段 inject 到每個用 Gemini 的 workflow Code node 開頭。
// 學員客製 workflow 時：
//   - 改 LP_CONFIG → 統一調整 model / timeout / retry / RPM
//   - 用 lpCall(...) 呼叫 LLM → 自動 throttle + retry + 429 處理
//   - 用 lpSizeOK(...) 預檢 inline data → 避免撞 20 MB API limit
//   - 用 lpThrottle() → loop 內呼叫之間 sleep
//
// 換 LLM provider（Gemini → Claude / OpenAI）：只改 lpCall 內的 url/headers/body shape，
// 業務邏輯不動。
// ════════════════════════════════════════════════════════════
const LP = {
  apiKey: $env.GEMINI_API_KEY,
  model: 'gemini-2.5-flash',
  endpoint: 'https://generativelanguage.googleapis.com/v1beta/models',
  rpmDelayMs: 6500,                       // Free tier 10 RPM；paid 改 1000
  maxRetries: 3,
  retry429Ms: 60000,                      // 429 等 60s（quota window）
  retry5xxMs: 5000,                       // 5xx 等 5s
  timeoutMs: 30000,
  maxInlineBytes: 18 * 1024 * 1024,       // 18 MB（保留 buffer to 20 MB hard limit）
};

const lpSleep = ms => new Promise(r => setTimeout(r, ms));

// 主呼叫：自動 retry 429/5xx
// 用法：const r = await lpCall.call(this, { prompt, gen: { maxOutputTokens: 200 } });
//      if (r.ok) use r.text; else use r.error
async function lpCall({ prompt, gen = {}, _att = 0 }) {
  if (!prompt || typeof prompt !== 'string') return { ok: false, text: '', error: 'empty prompt' };
  try {
    const r = await this.helpers.httpRequest({
      method: 'POST',
      url: LP.endpoint + '/' + LP.model + ':generateContent',
      headers: { 'Content-Type': 'application/json', 'x-goog-api-key': LP.apiKey },
      body: {
        contents: [{ role: 'user', parts: [{ text: prompt }] }],
        generationConfig: {
          temperature: 0.4, maxOutputTokens: 400, thinkingConfig: { thinkingBudget: 0 },
          ...gen
        }
      },
      json: true,
      timeout: LP.timeoutMs,
    });
    return {
      ok: true,
      text: r.candidates?.[0]?.content?.parts?.[0]?.text || '',
      finishReason: r.candidates?.[0]?.finishReason || 'unknown',
      attempt: _att,
    };
  } catch (e) {
    const m = (e && e.message) || String(e);
    const r429 = m.includes('429') || m.includes('RESOURCE_EXHAUSTED') || m.includes('quota');
    const r5xx = /\b5\d{2}\b/.test(m) || m.includes('UNAVAILABLE');
    if (_att < LP.maxRetries && (r429 || r5xx)) {
      await lpSleep(r429 ? LP.retry429Ms : LP.retry5xxMs);
      return lpCall.call(this, { prompt, gen, _att: _att + 1 });
    }
    return { ok: false, text: '', error: m.substring(0, 300), attempt: _att };
  }
}

// loop 內 N 筆呼叫之間 sleep（避免撞 RPM）
// 用法：for (let i = 0; i < items.length; i++) { if (i > 0) await lpThrottle(); ... }
async function lpThrottle() { await lpSleep(LP.rpmDelayMs); }

// 預檢 inline data 是否會撞 20 MB API request limit
// 用法：if (!lpSizeOK(binary.data.data)) { /* skip 或 chunk */ }
function lpSizeOK(base64OrBuf) {
  const b = typeof base64OrBuf === 'string'
    ? Math.floor(base64OrBuf.length * 0.75)
    : (base64OrBuf && base64OrBuf.length) || 0;
  return b <= LP.maxInlineBytes;
}

// ════════════════════════════════════════════════════════════
// 業務邏輯（這裡開始是這個 workflow 特有的）
// ════════════════════════════════════════════════════════════
// v0.9：Code node 直接打 Gemini API + 多份 PDF robust 對齊（用 binary.data.fileName 或 i 對齊 Read，不靠 pairedItem）

const today = new Date().toISOString().slice(0, 10).replace(/-/g, '');
const items = $input.all();
const allReadItems = $('Read PDF').all();
const results = [];

for (let idx = 0; idx < items.length; idx++) {
  const item = items[idx];
  if (idx > 0) await lpThrottle();  // v1.2: avoid 10 RPM Gemini Free tier 429

  // 找對應 Read item：先用 binary.data.fileName，再用 i 對齊
  let readItem = null;
  const binFileName = item.binary?.data?.fileName;
  if (binFileName) {
    readItem = allReadItems.find(r => r?.json?.fileName === binFileName);
  }
  if (!readItem) {
    readItem = allReadItems[idx];
  }

  const pdfText = item.json.text || '';
  const originalName = readItem?.json?.fileName || 'unknown.pdf';
  const originalPath = '/files/shared/pdf-inbox/' + originalName;

  if (!readItem?.binary?.data) {
    throw new Error('[idx=' + idx + '] No binary. originalName=' + originalName + ', binFileName=' + binFileName + ', readNames=[' + allReadItems.map(r => r?.json?.fileName).join('|') + ']');
  }

  const prompt = '請為這份 PDF 文件取一個語意化檔名（繁體中文）。\n格式：YYYYMMDD_類型_關鍵字\n- 日期：' + today + '\n- 類型 2-4 字（合約 / 發票 / 報告 / 說明 / 簡報 / 紀錄 / 手冊 / 規格）\n- 關鍵字 5-20 字\n範例：20260506_說明_Adobe創意服務\n直接回檔名一行（不要 markdown，不要引號，不要解釋文字）。\n\n<PDF>\n' + pdfText.substring(0, 2500) + '\n</PDF>';

  // v1.2.2: 用 lpCall（自動 retry 429/5xx），介面與舊 try/catch 對齊
  const lpResult = await lpCall.call(this, {
    prompt,
    gen: { temperature: 0.4, maxOutputTokens: 200 }
  });
  const aiResponse = lpResult.text || '';
  const finishReason = lpResult.finishReason || 'unknown';
  const httpError = lpResult.ok ? null : (lpResult.error || 'unknown error');

  let newFilename;
  let parseMethod;
  const trimmed = aiResponse.trim().replace(/^```\w*\n?/, '').replace(/\n?```$/, '').trim();
  if (trimmed && /^\d{8}[_\-]/.test(trimmed)) {
    newFilename = trimmed.split('\n')[0];
    parseMethod = 'ai-plain';
  }
  if (!newFilename) {
    const m = aiResponse.match(/(\d{8}[_\-][^\s"',\n]+)/);
    if (m) { newFilename = m[1]; parseMethod = 'regex-date'; }
  }
  if (!newFilename && pdfText) {
    const lines = pdfText.split('\n').map(l => l.trim()).filter(l => l.length > 3 && l.length < 80);
    let titleCandidate;
    for (const line of lines) {
      if (/^[\d\s\/:.\-]+$/.test(line)) continue;
      let cleanedLine = line.replace(/^\d+[\s\/:.\-]+\d+[\s\/:.\-]+\d+[\s\/:.\-]*\d*[\s\/:.\-]*\d*\s*/, '').trim();
      if (cleanedLine.length > 3) { titleCandidate = cleanedLine; break; }
    }
    if (titleCandidate) {
      const cleaned = titleCandidate.replace(/[—–\-—‧·•]/g, '_').replace(/\s+/g, '_').replace(/_+/g, '_').replace(/^_|_$/g, '').substring(0, 50);
      newFilename = today + '_文件_' + cleaned;
      parseMethod = 'pdf-title';
    }
  }
  if (!newFilename) {
    newFilename = today + '_AI無回應_' + originalName.replace(/\.pdf$/i, '');
    parseMethod = httpError ? ('http-error: ' + httpError.substring(0, 80)) : ('fallback-empty(finish=' + finishReason + ')');
  }
  newFilename = newFilename.replace(/[\\/:*?"<>|]/g, '_').replace(/\.pdf$/i, '').substring(0, 100);

  results.push({
    json: {
      originalPath, originalName, newFilename,
      newPath: '/files/shared/pdf-renamed/' + newFilename + '.pdf',
      parseMethod, finishReason,
      aiResponseLength: aiResponse.length,
      aiResponsePreview: aiResponse.substring(0, 200),
      pdfTextLength: pdfText.length,
      pdfTextPreview: pdfText.substring(0, 200),
      httpError
    },
    binary: readItem?.binary,
    pairedItem: { item: idx }
  });
}

return results;
